--- a/llvm/lib/IR/ConstantRange.cpp
+++ b/llvm/lib/IR/ConstantRange.cpp
@@ -1524,6 +1524,38 @@ ConstantRange ConstantRange::binaryAnd(const ConstantRange &Other) const {
   if (isEmptySet() || Other.isEmptySet())
     return getEmpty();

+  // Special case: if one operand is a constant, we can sometimes prove the
+  // result cannot be zero. This happens when the range is upper-wrapped
+  // (extends to max) and the lower bound is greater than ~constant.
+  if (Other.isSingleElement()) {
+    const APInt &C = *Other.getSingleElement();
+    if (isUpperWrapped()) {
+      APInt NotC = ~C;
+      if (getUnsignedMin().ugt(NotC)) {
+        // The result cannot be 0. Return a range starting from at least 1.
+        ConstantRange KnownBitsRange =
+            fromKnownBits(toKnownBits() & Other.toKnownBits(), false);
+        ConstantRange UMinUMaxRange =
+            getNonEmpty(APInt(getBitWidth(), 1),
+                        APIntOps::umin(Other.getUnsignedMax(), getUnsignedMax()) + 1);
+        return KnownBitsRange.intersectWith(UMinUMaxRange);
+      }
+    }
+  }
+  if (isSingleElement() && Other.isUpperWrapped()) {
+    const APInt &C = *getSingleElement();
+    APInt NotC = ~C;
+    if (Other.getUnsignedMin().ugt(NotC)) {
+      // The result cannot be 0.
+      ConstantRange KnownBitsRange =
+          fromKnownBits(toKnownBits() & Other.toKnownBits(), false);
+      ConstantRange UMinUMaxRange =
+          getNonEmpty(APInt(getBitWidth(), 1),
+                      APIntOps::umin(Other.getUnsignedMax(), getUnsignedMax()) + 1);
+      return KnownBitsRange.intersectWith(UMinUMaxRange);
+    }
+  }
